<?php require_once __DIR__.'/../config/database.php'; require_once __DIR__.'/../includes/functions.php'; require_login(); $where=[];$p=[]; if((current_user()['role_name']??'')!=='admin'){ $where[]='c.user_id=?'; $p[]=current_user()['id']; } foreach(['status'=>'d.diagnosis','location'=>'c.location'] as $k=>$col){ if(!empty($_GET[$k])){ $where[]="$col LIKE ?"; $p[]='%'.$_GET[$k].'%'; }} if(!empty($_GET['date'])){ $where[]='DATE(c.created_at)=?'; $p[]=$_GET['date']; } $sql='SELECT c.*,u.name,d.diagnosis,r.code rule_code FROM consultations c JOIN users u ON u.id=c.user_id JOIN diagnosis_results d ON d.consultation_id=c.id LEFT JOIN rules r ON r.id=d.rule_id'.($where?' WHERE '.implode(' AND ',$where):'').' ORDER BY c.created_at DESC'; $stmt=$pdo->prepare($sql); $stmt->execute($p); $rows=$stmt->fetchAll(); if(isset($_GET['export'])){ header('Content-Type:text/csv'); header('Content-Disposition:attachment; filename=laporan.csv'); echo "Tanggal,Lokasi,User,Status,Rule\n"; foreach($rows as $r) echo "{$r['created_at']},{$r['location']},{$r['name']},{$r['diagnosis']},{$r['rule_code']}\n"; exit; } require_once __DIR__.'/../includes/header.php'; ?>
<div class="container px-3 px-lg-4"><div class="d-flex flex-column flex-lg-row justify-content-between gap-3 mb-4"><div><h2 class="section-title mb-1">Riwayat Konsultasi</h2><p class="text-muted mb-0">Telusuri, cetak, dan ekspor hasil diagnosis potensi banjir.</p></div><a class="btn btn-primary align-self-start" href="<?=app_url('konsultasi/index.php')?>"><i class="bi bi-plus-circle me-2"></i>Konsultasi Baru</a></div><form class="card p-3 mb-3"><div class="row g-2"><div class="col-md-3"><input type="date" name="date" class="form-control" value="<?=e($_GET['date']??'')?>"></div><div class="col-md-3"><input name="location" class="form-control" placeholder="Lokasi" value="<?=e($_GET['location']??'')?>"></div><div class="col-md-3"><select name="status" class="form-select"><option value="">Semua Status</option><?php foreach(['Rendah','Sedang','Tinggi','Sangat Tinggi'] as $s): ?><option <?=($_GET['status']??'')===$s?'selected':''?>><?=$s?></option><?php endforeach; ?></select></div><div class="col-md-3 d-flex gap-2"><button class="btn btn-primary flex-fill">Filter</button><button name="export" value="csv" class="btn btn-success" title="CSV"><i class="bi bi-file-earmark-spreadsheet"></i></button><button type="button" class="btn btn-outline-secondary" data-print><i class="bi bi-printer"></i></button></div></div></form><div class="table-wrap"><table class="table table-hover"><thead><tr><th>Tanggal</th><th>Lokasi</th><th>User</th><th>Status</th><th>Rule</th><th>Detail</th></tr></thead><tbody><?php foreach($rows as $r): $riskClass='risk-'.strtolower(str_replace(' ','-', $r['diagnosis'])); ?><tr><td><?=e($r['created_at'])?></td><td><?=e($r['location'])?></td><td><?=e($r['name'])?></td><td><span class="badge-risk <?=$riskClass?>"><?=e($r['diagnosis'])?></span></td><td><?=e($r['rule_code'] ?: 'R-DEFAULT')?></td><td><a class="btn btn-sm btn-outline-primary" href="<?=app_url('hasil/index.php?id='.(int)$r['id'])?>">Lihat</a></td></tr><?php endforeach; ?></tbody></table></div></div>
